import requests; from bs4 import BeautifulSoup; import re

url = 'https://www.notion.so/pricing'
try:
    headers = {'User-Agent': 'Mozilla/5.0'}
    response = requests.get(url, headers=headers, timeout=10)
    soup = BeautifulSoup(response.text, 'html.parser')
    text = soup.get_text()

    # 提取关键信息：免费/个人/团队/企业计划和功能特点
def extract_info(text):
    lines = [l.strip() for l in text.split('\n') if l.strip()]
    info = {'pricing': [], 'features': []}

    for i, line in enumerate(lines):
        # 定价
        if 'free' in line.lower() or '个人' in line or '团队' in line or 'enterprise' in line.lower():
            if i+1 < len(lines) and ('$' in lines[i+1] or '¥' in lines[i+1] or '元' in lines[i+1]):
                info['pricing'].append(f"{line}: {lines[i+1]}")
        # 功能
        if 'blocks' in line.lower() or 'databases' in line.lower() or 'collaboration' in line.lower():
            info['features'].append(line)

    return info

print(extract_info(text))
except Exception as e:
    print(f"Error: {e}")

